for idx, s in enumerate(train_samples):
    inp = np.array(s['input'])
    out = np.array(s['output'])
    print(f"\n=== Example {idx} ===")

    colors = sorted(set(int(x) for x in inp.flatten() if x != 8))
    structure = np.ones((3,3))

    frame_parts = {}
    scattered = {}

    for c in colors:
        mask = (inp == c)
        labeled, num = ndimage.label(mask, structure=structure)
        for comp_id in range(1, num+1):
            comp_cells = np.array(list(zip(*np.where(labeled == comp_id))))
            if len(comp_cells) == 2:
                frame_parts[c] = comp_cells
            else:
                rows = comp_cells[:,0]
                cols = comp_cells[:,1]
                r_min, r_max = int(rows.min()), int(rows.max())
                c_min, c_max = int(cols.min()), int(cols.max())
                shape = np.zeros((r_max-r_min+1, c_max-c_min+1), dtype=int)
                for r, c2 in comp_cells:
                    shape[r-r_min, c2-c_min] = 1
                scattered[c] = shape

    # Frame properties
    all_frame_cells = []
    for c, cells in frame_parts.items():
        for cell in cells:
            all_frame_cells.append((int(cell[0]), int(cell[1]), c))

    all_rows = [x[0] for x in all_frame_cells]
    all_cols = [x[1] for x in all_frame_cells]
    r_min_f, r_max_f = min(all_rows), max(all_rows)
    c_min_f, c_max_f = min(all_cols), max(all_cols)

    sides = {}
    for c, cells in frame_parts.items():
        r_avg = np.mean(cells[:,0])
        c_avg = np.mean(cells[:,1])
        if cells[0][0] == cells[1][0]:
            if r_avg <= (r_min_f + r_max_f) / 2:
                sides['top'] = c
            else:
                sides['bottom'] = c
        else:
            if c_avg <= (c_min_f + c_max_f) / 2:
                sides['left'] = c
            else:
                sides['right'] = c

    # For each side with a scattered shape, extract the output extension
    for side_name, color in sides.items():
        if color not in scattered:
            continue

        scat_shape = scattered[color]

        # Extract output shape for this color
        out_mask = (out == color)
        out_cells = np.array(list(zip(*np.where(out_mask))))
        r_min_o = int(out_cells[:,0].min())
        r_max_o = int(out_cells[:,0].max())
        c_min_o = int(out_cells[:,1].min())
        c_max_o = int(out_cells[:,1].max())

        out_shape = np.zeros((r_max_o-r_min_o+1, c_max_o-c_min_o+1), dtype=int)
        for r, c2 in out_cells:
            out_shape[r-r_min_o, c2-c_min_o] = 1

        # Exclude frame cells from output shape
        # Actually, let me include them - the output includes both frame + extension

        print(f"\n  Side: {side_name}, color: {color}")
        print(f"  Scattered shape ({scat_shape.shape}):")
        for row in scat_shape:
            print(f"    {row.tolist()}")
        print(f"  Output total shape ({out_shape.shape}) at ({r_min_o},{c_min_o}):")
        for row in out_shape:
            print(f"    {row.tolist()}")

