def solve(grid):
    import numpy as np
    from scipy import ndimage

    grid = np.array(grid)
    H, W = grid.shape
    bg = 8
    output = np.full_like(grid, bg)

    colors = sorted(set(int(x) for x in grid.flatten() if x != bg))
    struct = np.ones((3,3))

    frame_parts = {}
    scattered = {}

    for c in colors:
        mask = (grid == c)
        labeled, num = ndimage.label(mask, structure=struct)
        for comp_id in range(1, num+1):
            comp_cells = np.array(list(zip(*np.where(labeled == comp_id))))
            if len(comp_cells) == 2:
                if c not in frame_parts:
                    frame_parts[c] = comp_cells
            else:
                rows, cols = comp_cells[:,0], comp_cells[:,1]
                r_min, r_max = int(rows.min()), int(rows.max())
                c_min, c_max = int(cols.min()), int(cols.max())
                shape = np.zeros((r_max-r_min+1, c_max-c_min+1), dtype=int)
                for r, c2 in comp_cells:
                    shape[r-r_min, c2-c_min] = 1
                scattered[c] = shape

    all_frame = []
    for c, cells in frame_parts.items():
        for cell in cells:
            all_frame.append((int(cell[0]), int(cell[1])))

    frame_rows = [x[0] for x in all_frame]
    frame_cols = [x[1] for x in all_frame]
    fr_min, fr_max = min(frame_rows), max(frame_rows)
    fc_min, fc_max = min(frame_cols), max(frame_cols)

    sides = {}
    for c, cells in frame_parts.items():
        if cells[0][0] == cells[1][0]:
            r_avg = float(cells[0][0])
            side = 'top' if r_avg < (fr_min + fr_max) / 2 else 'bottom'
        else:
            c_avg = float(cells[0][1])
            side = 'left' if c_avg < (fc_min + fc_max) / 2 else 'right'
        sides[side] = c

    # Place frame edges
    for c, cells in frame_parts.items():
        for cell in cells:
            output[int(cell[0]), int(cell[1])] = c

    frame_height = fr_max - fr_min + 1

    for side, color in sides.items():
        if color not in scattered:
            continue

        scat = scattered[color]

        orientations = []
        for k in range(4):
            rotated = np.rot90(scat, k=k)
            orientations.append(rotated)
            orientations.append(np.fliplr(rotated))

        best = None
        best_col_start = None

        for orient in orientations:
            oh, ow = orient.shape

            if side in ('left', 'right'):
                if oh != frame_height:
                    continue
                if side == 'left':
                    col = orient[:, -1].tolist()
                    if col == [0, 1, 1, 0]:
                        best = orient
                        break
                else:
                    col = orient[:, 0].tolist()
                    if col == [0, 1, 1, 0]:
                        best = orient
                        break
            else:
                if side == 'top':
                    row = orient[-1, :]
                else:
                    row = orient[0, :]

                first_1 = -1
                for i in range(len(row)):
                    if row[i] == 1:
                        first_1 = i
                        break
                if first_1 < 0:
                    continue

                col_start = fc_min + 1 - first_1

                four_span = [0, 0, 0, 0]
                valid = True
                for i in range(len(row)):
                    pos = i + col_start - fc_min
                    if pos < 0 or pos >= 4:
                        if row[i] == 1:
                            valid = False
                            break
                    else:
                        four_span[pos] = int(row[i])

                if valid and four_span == [0, 1, 1, 0]:
                    best = orient
                    best_col_start = col_start
                    break

        if best is None:
            continue

        oh, ow = best.shape

        if side == 'right':
            for r in range(oh):
                for c in range(ow):
                    if best[r, c]:
                        gr = fr_min + r
                        gc = fc_max + 1 + c
                        if 0 <= gr < H and 0 <= gc < W:
                            output[gr, gc] = color
        elif side == 'left':
            for r in range(oh):
                for c in range(ow):
                    if best[r, c]:
                        gr = fr_min + r
                        gc = fc_min - ow + c
                        if 0 <= gr < H and 0 <= gc < W:
                            output[gr, gc] = color
        elif side == 'top':
            for r in range(oh):
                for c in range(ow):
                    if best[r, c]:
                        gr = fr_min - oh + r
                        gc = best_col_start + c
                        if 0 <= gr < H and 0 <= gc < W:
                            output[gr, gc] = color
        elif side == 'bottom':
            for r in range(oh):
                for c in range(ow):
                    if best[r, c]:
                        gr = fr_max + 1 + r
                        gc = best_col_start + c
                        if 0 <= gr < H and 0 <= gc < W:
                            output[gr, gc] = color

    return output.tolist()

# Test on all training examples
for idx, s in enumerate(train_samples):
    result = solve(s['input'])
    expected = s['output']
    match = result == expected
    print(f"Example {idx}: {'PASS' if match else 'FAIL'}")
    if not match:
        result_arr = np.array(result)
        expected_arr = np.array(expected)
        diff = np.where(result_arr != expected_arr)
        print(f"  Differences at {len(diff[0])} positions")
        for i in range(min(5, len(diff[0]))):
            r, c = int(diff[0][i]), int(diff[1][i])
            print(f"    ({r},{c}): got {int(result_arr[r,c])}, expected {int(expected_arr[r,c])}")

